import React, { useState, useEffect, useCallback } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import ThemeToggle from './ThemeToggle';
import { 
  Cpu, LayoutDashboard, TrendingUp, LogOut, 
  Terminal, Menu, X, Globe, Archive 
} from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const { isDarkMode } = useTheme(); 
  const navigate = useNavigate();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);

  // Close mobile menu when route changes
  useEffect(() => {
    setMobileOpen(false);
  }, [location.pathname]);

  // Handle Escape key to close mobile menu
  useEffect(() => {
    const handleEsc = (e) => {
      if (e.key === 'Escape') setMobileOpen(false);
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  const handleLogout = useCallback(() => {
    logout();
    navigate('/login');
  }, [logout, navigate]);

  const isActive = (path) => location.pathname === path;

  // Memoized Style Generator
  const getNavLinkStyle = (path, isAccent = false) => {
    const active = isActive(path);
    return {
      textDecoration: 'none',
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      fontSize: '11px',
      fontWeight: 700,
      textTransform: 'uppercase',
      letterSpacing: '0.05em',
      padding: '0.5rem 0.8rem',
      borderRadius: '10px',
      transition: 'all 0.25s cubic-bezier(0.4, 0, 0.2, 1)',
      cursor: 'pointer',
      whiteSpace: 'nowrap',
      ...(isAccent ? {
        background: 'var(--accent-primary)',
        color: '#000',
        boxShadow: '0 0 15px var(--accent-glow)',
        border: '1px solid var(--accent-primary)',
      } : active ? {
        backgroundColor: 'var(--accent-muted)',
        color: 'var(--accent-primary)',
        border: '1px solid var(--accent-primary)',
      } : {
        backgroundColor: 'transparent',
        color: 'var(--text-secondary)',
        border: '1px solid transparent',
      }),
    };
  };

  return (
    <header style={{ position: 'sticky', top: 0, zIndex: 1000, padding: '1rem' }}>
      <nav 
        aria-label="Main Navigation"
        style={{
          maxWidth: '1200px',
          margin: '0 auto',
          background: 'var(--surface-glass)',
          backdropFilter: 'blur(18px)',
          WebkitBackdropFilter: 'blur(18px)',
          border: '1px solid var(--surface-border)',
          borderRadius: '18px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          padding: '0.6rem 1.2rem',
          boxShadow: 'var(--shadow-elevated)',
          transition: 'background-color 0.3s ease, border-color 0.3s ease'
        }}
      >
        {/* ── Brand ── */}
        <Link 
          to="/" 
          style={{ display: 'flex', alignItems: 'center', gap: '10px', textDecoration: 'none', color: 'var(--text-primary)' }}
          aria-label="Finify AI Home"
        >
          <div style={{
            width: '34px', height: '34px', borderRadius: '10px',
            background: 'var(--accent-muted)', border: '1px solid var(--accent-primary)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            boxShadow: '0 0 12px var(--accent-glow)'
          }}>
            <Cpu size={18} color="var(--accent-primary)" />
          </div>
          <span style={{ fontWeight: 800, fontSize: '0.9rem', letterSpacing: '0.12em', color: 'var(--text-primary)' }}>
            FINIFY_AI
          </span>
        </Link>

        {/* ── Desktop Navigation ── */}
        <div className="nav-desktop" style={{ display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
          {user ? (
            <>
              <Link to="/dashboard" style={getNavLinkStyle('/dashboard')}>
                <LayoutDashboard size={14}/> Dashboard
              </Link>
              <Link to="/generate" style={getNavLinkStyle('/generate')}>
                <TrendingUp size={14}/> Strategy
              </Link>
              <Link to="/live" style={getNavLinkStyle('/live')}>
                <Globe size={14}/> Live_Pulse
              </Link>
              <Link to="/vault" style={getNavLinkStyle('/vault')}>
                <Archive size={14}/> Vault
              </Link>
              <div style={{ width: '1px', height: '20px', background: 'var(--surface-border)', margin: '0 0.5rem' }} />
              <ThemeToggle />
              <button 
                onClick={handleLogout} 
                style={logoutButtonStyle}
                aria-label="Log out"
              >
                <LogOut size={16} />
              </button>
            </>
          ) : (
            <>
              <Link to="/login" style={getNavLinkStyle('/login')}>
                <Terminal size={14}/> Access
              </Link>
              <Link to="/register" style={getNavLinkStyle('/register', true)}>
                Initialize
              </Link>
              <ThemeToggle />
            </>
          )}
        </div>

        {/* ── Mobile Toggle ── */}
        <button 
          className="nav-mobile-toggle" 
          onClick={() => setMobileOpen(!mobileOpen)} 
          aria-expanded={mobileOpen}
          aria-label="Toggle mobile menu"
          style={{ 
            display: 'none', 
            background: 'none', 
            border: 'none', 
            color: 'var(--text-primary)', 
            cursor: 'pointer',
            padding: '8px'
          }}
        >
          {mobileOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </nav>

      {/* ── Mobile Menu ── */}
      {mobileOpen && (
        <div 
          className="reveal-node"
          style={{
            position: 'absolute',
            top: '100%',
            left: '1rem',
            right: '1rem',
            marginTop: '0.5rem',
            background: 'var(--surface-glass)',
            backdropFilter: 'blur(20px)',
            border: '1px solid var(--surface-border)',
            borderRadius: '16px',
            padding: '1rem',
            display: 'flex',
            flexDirection: 'column',
            gap: '0.6rem',
            boxShadow: 'var(--shadow-elevated)',
            animation: 'fadeInSlide 0.3s ease'
          }}
        >
          {user ? (
            <>
              <Link to="/dashboard" style={getNavLinkStyle('/dashboard')}>Dashboard</Link>
              <Link to="/generate" style={getNavLinkStyle('/generate')}>Strategy</Link>
              <Link to="/live" style={getNavLinkStyle('/live')}>Live Pulse</Link>
              <Link to="/vault" style={getNavLinkStyle('/vault')}>Vault</Link>
              <div style={{ height: '1px', background: 'var(--surface-border)', margin: '0.5rem 0' }} />
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <ThemeToggle />
                <button onClick={handleLogout} style={{ ...getNavLinkStyle('', false), color: '#ef4444' }}>
                  <LogOut size={14} /> EXIT_SESSION
                </button>
              </div>
            </>
          ) : (
            <>
              <Link to="/login" style={getNavLinkStyle('/login')}>Access Terminal</Link>
              <Link to="/register" style={getNavLinkStyle('/register', true)}>Initialize Node</Link>
              <ThemeToggle />
            </>
          )}
        </div>
      )}

      <style>{`
        @media (max-width: 980px) {
          .nav-desktop { display: none !important; }
          .nav-mobile-toggle { display: block !important; }
        }
        @keyframes fadeInSlide {
          from { opacity: 0; transform: translateY(-10px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </header>
  );
};

const logoutButtonStyle = {
  background: 'rgba(239, 68, 68, 0.1)',
  border: '1px solid rgba(239, 68, 68, 0.2)',
  color: '#ef4444',
  cursor: 'pointer',
  padding: '0.5rem',
  borderRadius: '8px',
  display: 'flex',
  alignItems: 'center',
  transition: 'all 0.2s ease',
};

export default Navbar;
